15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	};
22	
23	const FIRST_INSURANCE_MULTIPLIER = 1.1;
24	const PROCESSING_FEE = 5;
25	const ROUNDING_PRECISION = 6;
26	
27	const quotePremium = (items: Item[]): number => {
28	  let total = 0;
29	  for (const item of items) {
30	    const base = BASE_PREMIUM[item.type];
31	    total += base * FIRST_INSURANCE_MULTIPLIER;
32	  }
33	  const totalWithFee = total + PROCESSING_FEE;
34	  return Math.ceil(Number(totalWithFee.toFixed(ROUNDING_PRECISION)));
35	};
36	
37	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
38	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
39	  return { results };
40	};
